    MJEnvironment_EnvironmentID.[Name] AS [Environment]
FROM
    [${flyway:defaultSchema}].[Report] AS r
LEFT OUTER JOIN
    [${flyway:defaultSchema}].[ReportCategory] AS MJReportCategory_CategoryID
  ON
    [r].[CategoryID] = MJReportCategory_CategoryID.[ID]
